import React from "react";
import { ReactComponent as OpenIcon } from "../assets/icon_open.svg";

export function GalleryLink({ to }) {
  return to ? (
    <a href={to} target="_blank" rel="noreferrer">
      <OpenIcon />
    </a>
  ) : null;
}

export function GallerySkills({ items }) {
  return (
    <div className="gallery-skills">
      <small>
        {items.map((item, i) => {
          return (
            <React.Fragment key={i}>
              <span>{item}</span>
            </React.Fragment>
          );
        })}
      </small>
    </div>
  );
}

export function Gallery({
  id,
  image,
  heading,
  subheading,
  items,
  to,
  children,
}) {
  const [showExpanded, setShowExpanded] = React.useState(false);

  const handleExpand = () => {
    setShowExpanded(true);
  };

  const handleUnExpand = () => {
    setShowExpanded(false);
  };

  return (
    <section className="gallery" id={id}>
      <div className="gallery-inner">
        <div className="gallery-item">
          <div className="gallery-text">
            <h3>
              {heading}
              <GalleryLink to={to} />
            </h3>
            <h4>{subheading}</h4>
            {children}
          </div>
          <GallerySkills items={items} to={to} />
        </div>

        {showExpanded ? (
          <div className="gallery-expanded">
            <img
              className="gallery-expanded-image"
              src={image}
              alt="Portfolio image"
              onClick={handleUnExpand}
            />
          </div>
        ) : (
          <img
            className="gallery-image"
            src={image}
            alt="Portfolio image"
            onClick={handleExpand}
          />
        )}
      </div>
    </section>
  );
}
