import React from "react";
import ReactGA from "react-ga4";
import { ReactComponent as HomeIcon } from "../assets/icon_home.svg";

function TopMenuItem({ children, to, active }) {
  return (
    <div
      className={`topmenu-item ${active ? "active" : ""}`}
      onClick={() => {
        document.getElementById(to).scrollIntoView({ behavior: "smooth" });
        ReactGA.send({ hitType: "pageview", page: `/${to}` });
      }}
    >
      {children}
    </div>
  );
}

export default function TopMenu({ active }) {
  console.log(active);
  return (
    <div className="topmenu">
      <TopMenuItem to="home" active={active === "home"}>
        <HomeIcon />
      </TopMenuItem>
      <TopMenuItem to="intro" active={active === "intro"}>
        Who am I?
      </TopMenuItem>
      <TopMenuItem to="portfolio" active={active === "portfolio"}>
        Portfolio
      </TopMenuItem>
      <TopMenuItem to="skills" active={active === "skills"}>
        What I do
      </TopMenuItem>
      <TopMenuItem to="contact" active={active === "contact"}>
        Contact
      </TopMenuItem>
    </div>
  );
}
