import React from "react";
import { useWindowSize } from "./useWindowResize";
import { Fade } from "react-awesome-reveal";
import ReactGA from "react-ga4";

import WhoAmI from "./Components/WhoAmI";
import Contact from "./Components/Contact";
import Skills from "./Components/Skills";
import TopMenu from "./Components/TopMenu";
import { Gallery } from "./Components/Gallery";

import imgPrompter from "./assets/prompter.png";
import imgWahzaa1 from "./assets/wahzaa1.png";
import imgCampaign from "./assets/campaign.png";
import "./App.css";

function isInViewport(elt) {
  if (!elt) return;

  const rect = elt.getBoundingClientRect();
  return rect.top >= 0 && rect.top <= 100;
}

export default function App() {
  const [active, setActive] = React.useState(null);
  const windowSize = useWindowSize();
  let eltHome,
    eltIntro,
    eltPortfolio,
    eltSkills,
    eltContact = null;

  const handleScrollEvent = () => {
    if (isInViewport(eltHome)) setActive("home");
    if (isInViewport(eltIntro)) setActive("intro");
    if (isInViewport(eltPortfolio)) setActive("portfolio");
    if (isInViewport(eltSkills)) setActive("skills");
    if (isInViewport(eltContact)) setActive("contact");
  };

  React.useEffect(() => {
    ReactGA.send("pageview");

    document
      .getElementById("main")
      .addEventListener("scroll", handleScrollEvent);

    eltHome = document.getElementById("home");
    eltIntro = document.getElementById("intro");
    eltPortfolio = document.getElementById("portfolio");
    eltSkills = document.getElementById("skills");
    eltContact = document.getElementById("contact");
  });

  console.log(windowSize);

  return (
    <div className="app">
      <TopMenu active={active} />
      <main id="main">
        <WhoAmI state="home" />
        <Fade>
          <WhoAmI state="intro" />
          <Gallery
            id="portfolio"
            image={imgWahzaa1}
            heading="Wahzaa"
            subheading="Full-stack developer"
            items={[
              "React",
              "Node",
              "Express",
              "MongoDB",
              "Azure Functions",
              "Stripe",
            ]}
            to={"https://www.wahzaa.com"}
          >
            <p>
              Design and development, both frontend and backend, of
              subscription-based SaaS in the music tech industry. Very high
              requirements on performance and usability. Integration with
              various systems including Stripe for recurring payments.
            </p>
          </Gallery>
          <Gallery
            image={imgPrompter}
            heading="Prompter"
            subheading="Full-stack developer"
            items={["React", "Node", "Azure Functions", "MongoDB"]}
            to={"https://www.prompter.se"}
          >
            <p>
              Design and development of complex text analytics service based on
              DISC-profiles. Frontend built as an Microsoft Outlook Add-on.
              Backend built on NodeJS and Azure Functions using several online
              AI-services for natural language analytics services.
            </p>
          </Gallery>
          <Gallery
            image={imgCampaign}
            heading="Campaign site"
            subheading="Full-stack developer"
            items={["React", "Node", "Express", "MongoDB"]}
          >
            <p>
              Design and development of dynamic content campaign site. The
              campaign site allows for quick development and testing of
              campaign- and landing pages.
            </p>
          </Gallery>
          <Skills />
          <Contact />
        </Fade>
      </main>
    </div>
  );
}
